<script setup lang="ts">
import { Head } from '@inertiajs/vue3';
import { Check, ChevronRight, CircleAlert, Eye, FileWarning, Flag, Image, RefreshCw, ShieldCheck, Sparkles, Video, X } from '@lucide/vue';
import { computed, onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';

type Queue = { reports:any[]; media:any[]; videos:any[]; appeals:any[] };
const queue=ref<Queue>({reports:[],media:[],videos:[],appeals:[]}),loading=ref(true),busy=ref(''),error=ref(''),notice=ref(''),tab=ref('reports'),notes=ref<Record<string,string>>({});
const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';
const tabs=computed(()=>[
    {key:'reports',label:'Reports',icon:Flag,count:queue.value.reports.length},
    {key:'media',label:'Media',icon:Image,count:queue.value.media.length},
    {key:'videos',label:'AI suggestions',icon:Sparkles,count:queue.value.videos.length},
    {key:'appeals',label:'Appeals',icon:FileWarning,count:queue.value.appeals.length},
]);
const total=computed(()=>tabs.value.reduce((sum,item)=>sum+item.count,0));
const request=async(url:string,options:RequestInit={})=>{const response=await fetch(url,{...options,credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf(),...(options.headers??{})}});const payload=await response.json().catch(()=>({}));if(!response.ok)throw new Error(payload.message||'Unable to update moderation.');return payload.data??payload};
const load=async()=>{loading.value=true;error.value='';try{queue.value=await request('/api/v1/admin/moderation')}catch(e:any){error.value=e.message}finally{loading.value=false}};
const act=async(kind:keyof Queue,item:any,status:string,extra:Record<string,string>={})=>{const id=String(item.public_id??item.id),key=`${kind}:${id}:${status}`;busy.value=key;error.value='';notice.value='';try{const singular=kind==='media'?'media':kind==='videos'?'videos':kind==='reports'?'reports':'appeals';await request(`/api/v1/admin/moderation/${singular}/${id}`,{method:'PATCH',body:JSON.stringify({status,notes:notes.value[id]||null,...extra})});queue.value[kind]=queue.value[kind].filter(entry=>String(entry.public_id??entry.id)!==id);notice.value='Decision saved and added to the moderation history.'}catch(e:any){error.value=e.message}finally{busy.value=''}};
const date=(value:string)=>value?new Date(value).toLocaleString('en-ZA',{dateStyle:'medium',timeStyle:'short'}):'Recently';
const label=(value:string)=>String(value||'unknown').replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase());
onMounted(load);
</script>

<template><Head title="Content moderation"/><AppShell><main class="moderation-page">
<header class="moderation-hero"><div><span><ShieldCheck/> TRUST & SAFETY</span><h1>Content moderation</h1><p>Review reports, media checks, AI suggestions, and athlete appeals from one focused workspace.</p></div><button :disabled="loading" @click="load"><RefreshCw :class="{spin:loading}"/>Refresh queue</button></header>
<section class="moderation-summary"><article><strong>{{total}}</strong><span>Items need attention</span></article><article><strong>{{queue.reports.length}}</strong><span>Community reports</span></article><article><strong>{{queue.appeals.length}}</strong><span>Appeals waiting</span></article><div><Sparkles/><p><b>Review thoughtfully.</b><br/>Every decision is recorded for accountability.</p></div></section>
<p v-if="notice" class="moderation-message success"><Check/>{{notice}}</p><p v-if="error" class="moderation-message error"><CircleAlert/>{{error}}</p>
<nav class="moderation-tabs"><button v-for="item in tabs" :key="item.key" :class="{active:tab===item.key}" @click="tab=item.key"><component :is="item.icon"/><span>{{item.label}}</span><b>{{item.count}}</b></button></nav>
<section class="moderation-queue">
<div v-if="loading" class="moderation-empty"><RefreshCw class="spin"/><h2>Loading the review queue</h2><p>Gathering the latest reports and content signals…</p></div>
<template v-else-if="tab==='reports'&&queue.reports.length"><article v-for="item in queue.reports" :key="item.public_id" class="moderation-card"><div class="moderation-card-icon report"><Flag/></div><div class="moderation-card-copy"><span>COMMUNITY REPORT · {{label(item.reason)}}</span><h2>{{item.reporter?.name||'Community member'}} reported {{item.evidence?.type||'content'}}</h2><p>{{item.details||'No additional details were supplied.'}}</p><div class="reported-evidence"><img v-if="item.evidence?.media_url&&item.evidence?.mime_type?.startsWith('image/')" :src="item.evidence.media_url" alt="Reported content preview"/><video v-else-if="item.evidence?.media_url&&item.evidence?.mime_type?.startsWith('video/')" :src="item.evidence.media_url" controls preload="metadata"/><div><small>REPORTED CONTENT</small><blockquote>{{item.evidence?.text||'This content is no longer available.'}}</blockquote><span v-if="item.evidence?.author">Posted by {{item.evidence.author}}</span><a v-if="item.evidence?.url" :href="item.evidence.url" target="_blank">Open original <ChevronRight/></a></div></div><small>{{date(item.created_at)}} · {{label(item.status)}}</small><textarea v-model="notes[item.public_id]" placeholder="Add private moderator notes…"/></div><div class="moderation-actions"><button :disabled="!!busy" @click="act('reports',item,'reviewing',{action:'assign_review'})"><Eye/>Reviewing</button><button class="approve" :disabled="!!busy" @click="act('reports',item,'resolved',{action:'resolve_report'})"><Check/>Resolve</button><button class="muted" :disabled="!!busy" @click="act('reports',item,'dismissed',{action:'dismiss_report'})"><X/>Dismiss</button></div></article></template>
<template v-else-if="tab==='media'&&queue.media.length"><article v-for="item in queue.media" :key="item.public_id" class="moderation-card"><div class="moderation-card-icon media"><Image/></div><div class="moderation-card-copy"><span>MEDIA REVIEW · {{label(item.kind)}}</span><h2>{{item.original_name||item.title||'Uploaded media'}}</h2><p>Uploaded by {{item.user?.name||'Unknown member'}} · {{label(item.moderation_status)}}</p><small>{{date(item.created_at)}}</small><textarea v-model="notes[item.public_id]" placeholder="Reason or internal note…"/></div><div class="moderation-actions"><a v-if="item.download_url" :href="item.download_url" target="_blank"><Eye/>Preview</a><button class="approve" :disabled="!!busy" @click="act('media',item,'approved')"><Check/>Approve</button><button class="danger" :disabled="!!busy" @click="act('media',item,'rejected')"><X/>Reject</button></div></article></template>
<template v-else-if="tab==='videos'&&queue.videos.length"><article v-for="item in queue.videos" :key="item.public_id" class="moderation-card"><div class="moderation-card-icon video"><Video/></div><div class="moderation-card-copy"><span>AI CONTENT SUGGESTION · SCORE {{item.sports_relevance_score??'—'}}</span><h2>{{item.caption||'SportsUniverse post'}}</h2><p>{{item.moderation_reason||'Automated analysis recommended a human review.'}}</p><small>{{item.user?.name||'Unknown creator'}} · {{date(item.moderation_analyzed_at)}}</small><textarea v-model="notes[item.public_id]" placeholder="Explain your decision…"/></div><div class="moderation-actions"><a :href="`/feed#${item.public_id}`" target="_blank"><Eye/>View post</a><button class="approve" :disabled="!!busy" @click="act('videos',item,'published')"><Check/>Keep</button><button class="danger" :disabled="!!busy" @click="act('videos',item,'hidden')"><X/>Hide</button></div></article></template>
<template v-else-if="tab==='appeals'&&queue.appeals.length"><article v-for="item in queue.appeals" :key="item.public_id" class="moderation-card"><div class="moderation-card-icon appeal"><FileWarning/></div><div class="moderation-card-copy"><span>ATHLETE APPEAL</span><h2>{{item.video?.caption||'Post review request'}}</h2><p>{{item.message}}</p><small>{{item.user?.name||'Unknown creator'}} · {{date(item.created_at)}}</small><textarea v-model="notes[item.public_id]" placeholder="Resolution note shared with the athlete…"/></div><div class="moderation-actions"><button class="approve" :disabled="!!busy" @click="act('appeals',item,'approved',{decision:'restore'})"><Check/>Restore post</button><button class="danger" :disabled="!!busy" @click="act('appeals',item,'denied',{decision:'remove'})"><X/>Uphold removal</button></div></article></template>
<div v-else class="moderation-empty"><ShieldCheck/><h2>All clear in {{tabs.find(item=>item.key===tab)?.label.toLowerCase()}}</h2><p>There are no items waiting in this queue.</p></div>
</section></main></AppShell></template>

<style scoped>
.moderation-page{width:min(1180px,100%);margin:auto;padding:2rem 2rem 6rem;color:#172033}.moderation-hero{display:flex;align-items:flex-end;justify-content:space-between;gap:2rem;padding:2rem;border-radius:24px;color:#fff;background:radial-gradient(circle at 88% 15%,#ef80b655,transparent 28%),linear-gradient(135deg,#111e33,#263d65 68%,#7358df)}.moderation-hero span{display:flex;gap:.4rem;align-items:center;color:#f5b8d8;font-size:.65rem;font-weight:900;letter-spacing:.13em}.moderation-hero span svg{width:17px}.moderation-hero h1{margin:.65rem 0 .35rem;font-size:clamp(2rem,4vw,3.3rem);letter-spacing:-.055em}.moderation-hero p{max-width:680px;margin:0;color:#d8e2f1;line-height:1.55}.moderation-hero button{display:flex;min-width:135px;gap:.45rem;align-items:center;justify-content:center;padding:.75rem 1rem;color:#293555;border:0;border-radius:12px;background:#fff;font-weight:850}.moderation-hero button svg{width:16px}.moderation-summary{display:grid;grid-template-columns:repeat(3,1fr) 1.4fr;gap:.8rem;margin:1rem 0}.moderation-summary article,.moderation-summary>div{padding:1rem;border:1px solid #e0e6ef;border-radius:16px;background:#fff}.moderation-summary article{display:grid}.moderation-summary strong{font-size:1.45rem}.moderation-summary span{color:#7a8698;font-size:.65rem}.moderation-summary>div{display:flex;gap:.7rem;align-items:center;color:#75557a;background:#fff7fb}.moderation-summary>div svg{width:24px;color:#d64f94}.moderation-summary p{margin:0;font-size:.64rem;line-height:1.45}.moderation-message{display:flex;gap:.45rem;align-items:center;padding:.8rem 1rem;border-radius:12px;font-size:.7rem}.moderation-message svg{width:16px}.moderation-message.success{color:#277252;background:#eaf8f1}.moderation-message.error{color:#a52f51;background:#fff0f4}.moderation-tabs{display:flex;gap:.35rem;overflow:auto;margin:1.2rem 0;padding:.35rem;border-radius:14px;background:#e9eef5}.moderation-tabs button{display:flex;min-width:max-content;gap:.4rem;align-items:center;padding:.65rem .8rem;color:#697689;border:0;border-radius:10px;background:transparent;font-weight:750}.moderation-tabs button.active{color:#476FEA;background:#fff;box-shadow:0 3px 10px #273d6412}.moderation-tabs svg{width:15px}.moderation-tabs b{display:grid;min-width:20px;height:20px;place-items:center;border-radius:999px;background:#dfe6f2;font-size:.55rem}.moderation-tabs .active b{color:#fff;background:#476FEA}.moderation-queue{display:grid;gap:.75rem}.moderation-card{display:grid;grid-template-columns:48px minmax(0,1fr) auto;gap:1rem;padding:1rem;border:1px solid #e0e6ef;border-radius:18px;background:#fff;box-shadow:0 10px 28px #1b2d4b0d}.moderation-card-icon{display:grid;width:48px;height:48px;place-items:center;border-radius:14px}.moderation-card-icon svg{width:22px}.moderation-card-icon.report{color:#c43a67;background:#fff0f5}.moderation-card-icon.media{color:#476FEA;background:#edf3ff}.moderation-card-icon.video{color:#8051c7;background:#f3edff}.moderation-card-icon.appeal{color:#a56d13;background:#fff5dc}.moderation-card-copy{display:grid;gap:.25rem}.moderation-card-copy>span{color:#7c67c4;font-size:.52rem;font-weight:900;letter-spacing:.08em}.moderation-card h2{margin:0;font-size:.82rem}.moderation-card p{margin:.1rem 0;color:#59677b;font-size:.68rem;line-height:1.5}.moderation-card small{color:#8b96a6;font-size:.56rem}.moderation-card textarea{min-height:58px;margin-top:.45rem;padding:.6rem;border:1px solid #dbe2ec;border-radius:10px;resize:vertical;font:inherit;font-size:.63rem}.moderation-actions{display:flex;min-width:132px;gap:.4rem;align-items:stretch;justify-content:center;flex-direction:column}.moderation-actions button,.moderation-actions a{display:flex;min-height:34px;gap:.35rem;align-items:center;justify-content:center;padding:.45rem .65rem;color:#4f5e72;border:0;border-radius:9px;background:#f0f3f7;font-size:.58rem;font-weight:800;text-decoration:none}.moderation-actions svg{width:14px}.moderation-actions .approve{color:#17704d;background:#e8f8f0}.moderation-actions .danger{color:#ac3154;background:#ffedf3}.moderation-actions .muted{color:#76667a;background:#f5f0f5}.moderation-empty{display:grid;min-height:300px;place-content:center;justify-items:center;color:#7d899a;text-align:center;border:1px dashed #cbd5e2;border-radius:20px;background:#f8fafc}.moderation-empty>svg{width:38px;color:#8a77cc}.moderation-empty h2{margin:.8rem 0 .2rem;color:#253247}.moderation-empty p{margin:0;font-size:.68rem}.spin{animation:spin .8s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}@media(max-width:760px){.moderation-page{padding:1rem .85rem 6rem}.moderation-hero{align-items:flex-start;flex-direction:column;padding:1.4rem}.moderation-hero button{width:100%}.moderation-summary{grid-template-columns:repeat(3,1fr)}.moderation-summary>div{display:none}.moderation-card{grid-template-columns:42px minmax(0,1fr)}.moderation-card-icon{width:42px;height:42px}.moderation-actions{display:grid;grid-column:1/-1;grid-template-columns:repeat(3,1fr)} }
.reported-evidence{display:flex;gap:.75rem;margin:.55rem 0;padding:.75rem;border:1px solid #e3e8f0;border-left:4px solid #d64f94;border-radius:12px;background:#f8fafc}.reported-evidence>img,.reported-evidence>video{width:110px;height:90px;object-fit:cover;border-radius:9px;background:#101827}.reported-evidence>div{display:grid;flex:1;gap:.2rem}.reported-evidence small{color:#b63d7c!important;font-size:.5rem!important;font-weight:900;letter-spacing:.09em}.reported-evidence blockquote{margin:.1rem 0;color:#273449;font-size:.7rem;font-weight:650;line-height:1.45}.reported-evidence span{color:#7e8999;font-size:.56rem}.reported-evidence a{display:flex;width:max-content;gap:.2rem;align-items:center;color:#476FEA;font-size:.58rem;font-weight:800;text-decoration:none}.reported-evidence a svg{width:13px}@media(max-width:560px){.reported-evidence{align-items:stretch;flex-direction:column}.reported-evidence>img,.reported-evidence>video{width:100%;height:180px}}
</style>
